package main

import (
	"fmt"
	"math/rand"
	"slices"
	"sort"
	"strconv"
	"strings"
	"time"
)

var (
	languageOptions = []string{"English", "German", "Ukrainian", "Russian"}

	punctuationRunes = []rune{
		' ', '\n', '.', ',', ':', ';', '!', '?', '-', '(', ')', '/', '\'', '"',
	}

	languageRuneSets = map[string]string{
		"English":   "REDACTED",
		"German":    "REDACTEDÄÖÜẞ0123456789",
		"Ukrainian": "АБВГҐДЕЄЖЗИІЇЙКЛМНОПРСТУФХЦЧШЩЬЮЯ0123456789",
		"Russian":   "АБВГДЕЁЖЗИЙКЛМНОПРСТУФХЦЧШЩЪЫЬЭЮЯ0123456789",
	}
)

type textStats struct {
	CharacterCount    int
	LineCount         int
	UnsupportedCount  int
	UnsupportedUnique []rune
	DisplayText       string
}

func normalizeValidationText(text string, uppercaseOnly bool) string {
	normalized := strings.ReplaceAll(text, "\r\n", "\n")
	if uppercaseOnly {
		normalized = strings.ToUpper(normalized)
	}
	return normalized
}

func sortedLanguages(languages []string) []string {
	unique := make([]string, 0, len(languages))
	seen := map[string]bool{}
	for _, lang := range languages {
		if !seen[lang] {
			seen[lang] = true
			unique = append(unique, lang)
		}
	}
	slices.Sort(unique)
	return unique
}

func supportedRunes(languages []string) map[rune]bool {
	supported := map[rune]bool{}
	for _, r := range punctuationRunes {
		supported[r] = true
	}
	for _, lang := range languages {
		for _, r := range languageRuneSets[lang] {
			supported[r] = true
		}
	}
	return supported
}

func analyzeText(text string, languages []string, uppercaseOnly, autoReplace bool) textStats {
	normalized := normalizeValidationText(text, uppercaseOnly)

	if normalized == "" {
		return textStats{
			LineCount:   1,
			DisplayText: "",
		}
	}

	supported := supportedRunes(languages)
	unsupportedSeen := map[rune]bool{}
	unsupportedUnique := make([]rune, 0, 8)
	out := strings.Builder{}
	charCount := 0

	for _, r := range normalized {
		charCount++
		if supported[r] {
			out.WriteRune(r)
			continue
		}

		if !unsupportedSeen[r] {
			unsupportedSeen[r] = true
			unsupportedUnique = append(unsupportedUnique, r)
		}

		if autoReplace {
			out.WriteRune('?')
		} else {
			out.WriteRune(r)
		}
	}

	lineCount := strings.Count(normalized, "\n") + 1
	return textStats{
		CharacterCount:    charCount,
		LineCount:         lineCount,
		UnsupportedCount:  len(unsupportedUnique),
		UnsupportedUnique: unsupportedUnique,
		DisplayText:       out.String(),
	}
}

func formatUnsupportedRunes(runes []rune) string {
	if len(runes) == 0 {
		return "none"
	}
	parts := make([]string, 0, len(runes))
	for _, r := range runes {
		parts = append(parts, string(r))
	}
	return strings.Join(parts, " ")
}

func buildValidationPreview(text string, languages []string, uppercaseOnly bool) string {
	normalized := normalizeValidationText(text, uppercaseOnly)
	if normalized == "" {
		return "(empty)"
	}

	supported := supportedRunes(languages)
	var out strings.Builder
	for _, r := range normalized {
		if supported[r] {
			out.WriteRune(r)
			continue
		}
		out.WriteString("[")
		out.WriteRune(r)
		out.WriteString("]")
	}
	return out.String()
}

func formatReplacementGuidance(unsupported []rune, autoReplace bool) string {
	if len(unsupported) == 0 {
		return "Replacement guidance: none"
	}

	parts := make([]string, 0, len(unsupported))
	for _, r := range unsupported {
		if autoReplace {
			parts = append(parts, fmt.Sprintf("%s -> ?", string(r)))
		} else {
			parts = append(parts, fmt.Sprintf("%s is unsupported", string(r)))
		}
	}

	if autoReplace {
		return "Auto-replace targets: " + strings.Join(parts, ", ")
	}
	return "Replacement guidance: " + strings.Join(parts, ", ")
}

func buildSupportedCharsetSummary(languages []string) string {
	combined := make([]rune, 0, 128)
	for r := range supportedRunes(languages) {
		combined = append(combined, r)
	}
	sort.Slice(combined, func(i, j int) bool { return combined[i] < combined[j] })

	return fmt.Sprintf(
		"Languages: %s\n\nSupported characters:\n%s",
		strings.Join(sortedLanguages(languages), ", "),
		string(combined),
	)
}

func ensureSeed(seed string) string {
	if strings.TrimSpace(seed) != "" {
		return strings.TrimSpace(seed)
	}

	rng := rand.New(rand.NewSource(time.Now().UnixNano()))
	return strconv.FormatInt(rng.Int63(), 10)
}

package main

import (
	"hash/fnv"
	"math"
	"math/rand"
	"sort"
	"strconv"
	"strings"
)

type animatedFrame struct {
	Text  string
	Frame int
	Time  float64
}

func buildAnimatedFrame(project Project, stats textStats, frame int) animatedFrame {
	fps := maxInt(project.Export.FPS, 1)
	normalizedFrame := maxInt(frame-project.Export.StartFrame, 0)
	return animatedFrame{
		Text:  animateText(project, stats.DisplayText, normalizedFrame, fps),
		Frame: frame,
		Time:  float64(normalizedFrame) / float64(fps),
	}
}

func animateText(project Project, finalText string, frame, fps int) string {
	runes := []rune(finalText)
	animatable := animatablePositions(runes, project.Animation.ImmediatePunctuationLock)
	if len(animatable) == 0 {
		return finalText
	}

	introFrames := int(project.Animation.IntroDelay * float64(fps))
	outroFrames := int(project.Animation.OutroHold * float64(fps))
	totalFrames := maxInt(int(project.Animation.TotalDuration*float64(fps)), introFrames+outroFrames+1)
	finalLockFrame := maxInt(totalFrames-outroFrames, 1)

	if frame >= finalLockFrame {
		return finalText
	}

	perCharFrames := maxInt(int(project.Animation.PerCharacterDelay*float64(fps)), 1)
	scrambleWindow := maxInt(finalLockFrame/maxInt(len(animatable), 1), 3)
	scrambleWindow = maxInt(scrambleWindow, perCharFrames*2)
	order := orderIndices(animatable, runes, project.Animation.LockOrder, project.Animation.Seed)
	pool := buildRandomPool(project)
	seedBase := hashSeed(project.Animation.Seed)
	switchFrame := scrambleSwitchFrame(frame, project.Animation.RandomSwitchRate, fps)

	out := make([]rune, len(runes))
	copy(out, runes)

	for rank, idx := range order {
		r := runes[idx]
		if r == '\n' || r == ' ' || r == '\t' {
			continue
		}

		start := introFrames + rank*perCharFrames
		lockAt := minInt(start+scrambleWindow, finalLockFrame)
		if frame >= lockAt {
			continue
		}

		out[idx] = animateRuneForMode(project, pool, seedBase, frame, switchFrame, idx, r, start, lockAt, perCharFrames)
	}

	return string(out)
}

func animateRuneForMode(project Project, pool []rune, seedBase uint64, frame, switchFrame, index int, target rune, start, lockAt, perCharFrames int) rune {
	switch project.Animation.Type {
	case "Scramble basic":
		return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
	case "Reveal then scramble then lock":
		revealUntil := minInt(start+perCharFrames, lockAt)
		if frame < start {
			return ' '
		}
		if frame < revealUntil {
			return target
		}
		return lockOrScrambleRune(project, pool, seedBase, frame, switchFrame, index, target, revealUntil, lockAt)
	default:
		if frame < start {
			return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
		}
		return lockOrScrambleRune(project, pool, seedBase, frame, switchFrame, index, target, start, lockAt)
	}
}

func lockOrScrambleRune(project Project, pool []rune, seedBase uint64, frame, switchFrame, index int, target rune, start, lockAt int) rune {
	if project.Animation.SimultaneousFinalLock {
		return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
	}
	progress := float64(frame-start) / float64(maxInt(lockAt-start, 1))
	switch project.Animation.LockMode {
	case "Hard lock":
		return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
	default:
		if deterministicChance(seedBase, frame, index) < progress {
			return target
		}
		return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
	}
}

func buildRandomPool(project Project) []rune {
	switch project.Animation.RandomSource {
	case "Digits only":
		return []rune("0123456789")
	case "Letters only":
		return []rune("REDACTED")
	case "Alphanumeric":
		return []rune("REDACTED")
	default:
		pool := make([]rune, 0, 128)
		for r := range supportedRunes(project.Charset.Languages) {
			if r == '\n' || r == ' ' || r == '\t' {
				continue
			}
			if !project.Animation.AllowInvalidRandomChars && !isLetterOrDigit(r) {
				continue
			}
			pool = append(pool, r)
		}
		sort.Slice(pool, func(i, j int) bool { return pool[i] < pool[j] })
		if len(pool) == 0 {
			return []rune("REDACTED")
		}
		return pool
	}
}

func scrambleRune(pool []rune, seedBase uint64, switchFrame, index int, fallback rune, allowEmpty bool) rune {
	if allowEmpty && deterministicChance(seedBase, switchFrame, index+991) < 0.08 {
		return ' '
	}
	if len(pool) == 0 {
		return fallback
	}
	rng := rand.New(rand.NewSource(int64(seedBase) + int64(switchFrame*131) + int64(index*17)))
	return pool[rng.Intn(len(pool))]
}

func scrambleSwitchFrame(frame int, switchRate float64, fps int) int {
	if frame <= 0 || fps <= 0 {
		return 0
	}
	if switchRate <= 0 {
		return frame
	}
	return int(math.Floor(float64(frame) * switchRate / float64(fps)))
}

func deterministicChance(seedBase uint64, frame, index int) float64 {
	value := hashSeed(strconv.FormatUint(seedBase, 10) + ":" + strconv.Itoa(frame) + ":" + strconv.Itoa(index))
	return float64(value%1000) / 1000.0
}

func hashSeed(seed string) uint64 {
	h := fnv.New64a()
	if strings.TrimSpace(seed) == "" {
		seed = "default-seed"
	}
	_, _ = h.Write([]byte(seed))
	return h.Sum64()
}

func animatablePositions(runes []rune, immediatePunctuationLock bool) []int {
	positions := make([]int, 0, len(runes))
	for i, r := range runes {
		if r == '\n' {
			continue
		}
		if immediatePunctuationLock && shouldLockImmediately(r) {
			continue
		}
		positions = append(positions, i)
	}
	return positions
}

func orderIndices(positions []int, runes []rune, order, seed string) []int {
	ordered := append([]int(nil), positions...)
	switch order {
	case "Right-to-left":
		sort.SliceStable(ordered, func(i, j int) bool { return ordered[i] > ordered[j] })
	case "Center-out":
		center := float64(len(runes)-1) / 2.0
		sort.SliceStable(ordered, func(i, j int) bool {
			di := math.Abs(float64(ordered[i]) - center)
			dj := math.Abs(float64(ordered[j]) - center)
			if di == dj {
				return ordered[i] < ordered[j]
			}
			return di < dj
		})
	case "Random":
		rng := rand.New(rand.NewSource(int64(hashSeed(seed))))
		rng.Shuffle(len(ordered), func(i, j int) {
			ordered[i], ordered[j] = ordered[j], ordered[i]
		})
	case "By lines":
		type linePos struct {
			index    int
			line     int
			position int
		}
		seq := make([]linePos, 0, len(ordered))
		line := 0
		pos := 0
		for _, idx := range ordered {
			for cursor := 0; cursor < idx; cursor++ {
				if runes[cursor] == '\n' {
					line++
					pos = 0
				} else {
					pos++
				}
			}
			seq = append(seq, linePos{index: idx, line: line, position: pos})
			line = 0
			pos = 0
		}
		sort.SliceStable(seq, func(i, j int) bool {
			if seq[i].line == seq[j].line {
				return seq[i].position < seq[j].position
			}
			return seq[i].line < seq[j].line
		})
		for i, item := range seq {
			ordered[i] = item.index
		}
	default:
		sort.SliceStable(ordered, func(i, j int) bool { return ordered[i] < ordered[j] })
	}
	return ordered
}

func isLetterOrDigit(r rune) bool {
	return (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || (r >= 'А' && r <= 'я') || r == 'Ё' || r == 'Є' || r == 'Ї' || r == 'І' || r == 'Ґ' || r == 'Ä' || r == 'Ö' || r == 'Ü' || r == 'ẞ'
}

func shouldLockImmediately(r rune) bool {
	if r == '\n' || r == ' ' || r == '\t' {
		return false
	}
	return !isLetterOrDigit(r)
}

func minInt(a, b int) int {
	if a < b {
		return a
	}
	return b
}

