	charCount := 0

	for _, r := range normalized {
		charCount++
		if supported[r] {
			out.WriteRune(r)
			continue
		}

		if !unsupportedSeen[r] {
			unsupportedSeen[r] = true
			unsupportedUnique = append(unsupportedUnique, r)
		}

