func TestWriteSegmentPreview(t *testing.T) {
	project := normalizeProject(defaultProject())
	project.Text.Content = "LOLA: RENNT\nDIE: DEIN: LEBEN\nVERANDERN: KANN"
	project.Display.Mode = displayModeSegment
	project.Background.Mode = backgroundModeSolid
	project.Background.SolidColor = "#050608"
	project.Style.InactiveVisibility = 0
	stats := analyzeText(project.Text.Content, project.Charset.Languages, project.Text.UppercaseOnly, project.Text.AutoReplaceUnsupported)
	img, err := renderImage(project, stats, 119, 1280, 720)
	if err != nil {
		t.Fatal(err)
	}
	file, err := os.Create("/tmp/lolarennt-segment-preview.png")
	if err != nil {
		t.Fatal(err)
	}
	defer file.Close()
	if err := png.Encode(file, img); err != nil {
		t.Fatal(err)
	}
}

